  1→"use client";
  2→
  3→import { useState, useRef, useEffect, useCallback } from "react";
  4→import { Textarea } from "@/components/ui/textarea";
  5→import {
  6→  Send,
  7→  Loader2,
  8→  Shield,
  9→  ShieldAlert,
 10→  Bot,
 11→  User,
 12→  Sparkles,
 13→} from "lucide-react";
 14→import ReactMarkdown from "react-markdown";
 15→import { ChatMessage, ReviewMetadata } from "@/types";
 16→import { cn } from "@/lib/utils";
 17→
 18→interface ChatInterfaceProps {
 19→  sessionId: string;
 20→  metadata: ReviewMetadata;
 21→  compact?: boolean;
 22→}
 23→
 24→const SUGGESTED_QUESTIONS = [
 25→  "What are the most common complaints?",
 26→  "Summarize the positive reviews",
 27→  "What do customers say about quality?",
 28→  "Are there any recurring issues?",
 29→  "What features do reviewers mention most?",
 30→  "Compare 5-star vs 1-star review themes",
 31→];
 32→
 33→export default function ChatInterface({ sessionId, metadata, compact }: ChatInterfaceProps) {
 34→  const [messages, setMessages] = useState<ChatMessage[]>([]);
 35→  const [input, setInput] = useState("");
 36→  const [isStreaming, setIsStreaming] = useState(false);
 37→  const scrollContainerRef = useRef<HTMLDivElement>(null);
 38→  const messagesEndRef = useRef<HTMLDivElement>(null);
 39→  const textareaRef = useRef<HTMLTextAreaElement>(null);
 40→  const scrollToBottom = useCallback(() => {
 41→    messagesEndRef.current?.scrollIntoView({ behavior: "smooth" });
 42→  }, []);
 43→
 44→  // Auto-scroll on every message update (including streaming chunks)
 45→  useEffect(() => {
 46→    scrollToBottom();
 47→  }, [messages, scrollToBottom]);
 48→
 49→  const sendMessage = async (messageText?: string) => {
 50→    const text = messageText || input.trim();
 51→    if (!text || isStreaming) return;
 52→
 53→    const userMessage: ChatMessage = {
 54→      id: crypto.randomUUID(),
 55→      role: "user",
 56→      content: text,
 57→      timestamp: new Date().toISOString(),
 58→    };
 59→
 60→    setMessages((prev) => [...prev, userMessage]);
 61→    setInput("");
 62→    setIsStreaming(true);
 63→
 64→    const assistantId = crypto.randomUUID();
 65→    const assistantMessage: ChatMessage = {
 66→      id: assistantId,
 67→      role: "assistant",
 68→      content: "",
 69→      timestamp: new Date().toISOString(),
 70→    };
 71→    setMessages((prev) => [...prev, assistantMessage]);
 72→
 73→    try {
 74→      const history = messages.map((m) => ({
 75→        role: m.role,
 76→        content: m.content,
 77→      }));
 78→
 79→      // On first message, send session data so the server can hydrate its store
 80→      // (Turbopack runs route handlers in separate workers with isolated memory)
 81→      let sessionData: Record<string, unknown> | undefined;
 82→      if (messages.length === 0) {
 83→        try {
 84→          const reviews = JSON.parse(sessionStorage.getItem("reviewlens_reviews") || "[]");
 85→          const meta = JSON.parse(sessionStorage.getItem("reviewlens_metadata") || "{}");
 86→          const analytics = JSON.parse(sessionStorage.getItem("reviewlens_analytics") || "{}");
 87→          sessionData = { reviews, metadata: meta, analytics };
 88→        } catch { /* proceed without */ }
 89→      }
 90→
 91→      const response = await fetch("/api/chat", {
 92→        method: "POST",
 93→        headers: {
 94→          "Content-Type": "application/json",
 95→          "Accept-Encoding": "identity",
 96→          "Accept": "text/event-stream",
 97→        },
 98→        body: JSON.stringify({ sessionId, message: text, history, sessionData }),
 99→      });
100→
101→      if (!response.ok) throw new Error("Chat request failed");
102→
103→      const reader = response.body?.getReader();
104→      if (!reader) throw new Error("No response stream");
105→
106→      const decoder = new TextDecoder();
107→      let buffer = "";
108→
109→      for (;;) {
110→        const { done, value } = await reader.read();
111→        if (done) break;
112→
113→        buffer += decoder.decode(value, { stream: true });
114→
115→        let boundary = buffer.indexOf("\n\n");
116→        while (boundary !== -1) {
117→          const line = buffer.slice(0, boundary);
118→          buffer = buffer.slice(boundary + 2);
119→
120→          if (line.startsWith("data: ")) {
121→            try {
122→              const data = JSON.parse(line.slice(6));
123→              if (data.type === "text") {
124→                setMessages((prev) =>
125→                  prev.map((m) =>
126→                    m.id === assistantId ? { ...m, content: m.content + data.content } : m
127→                  )
128→                );
129→              } else if (data.type === "guard") {
130→                setMessages((prev) =>
131→                  prev.map((m) =>
132→                    m.id === assistantId
133→                      ? { ...m, content: data.content, scopeGuardTriggered: true, guardrailAction: data.action }
134→                      : m
135→                  )
136→                );
137→              } else if (data.type === "error") {
138→                setMessages((prev) =>
139→                  prev.map((m) =>
140→                    m.id === assistantId ? { ...m, content: data.content } : m
141→                  )
142→                );
143→              }
144→            } catch {
145→              /* skip invalid JSON */
146→            }
147→          }
148→
149→          boundary = buffer.indexOf("\n\n");
150→        }
151→      }
152→    } catch {
153→      setMessages((prev) =>
154→        prev.map((m) =>
155→          m.id === assistantId
156→            ? { ...m, content: "Sorry, something went wrong. Please try again." }
157→            : m
158→        )
159→      );
160→    } finally {
161→      setIsStreaming(false);
162→    }
163→  };
164→
165→  const handleKeyDown = (e: React.KeyboardEvent) => {
166→    if (e.key === "Enter" && !e.shiftKey) {
167→      e.preventDefault();
168→      sendMessage();
169→    }
170→  };
171→
172→  return (
173→    <div className={cn("flex flex-col", compact ? "h-full" : "h-[calc(100vh-10rem)]")}>
174→      {/* Chat header — hidden in compact/drawer mode */}
175→      {!compact && (
176→        <div className="glass-card rounded-xl px-4 py-3 mb-4 flex items-center gap-3">
177→          <div className="w-9 h-9 rounded-lg bg-linear-to-br from-emerald-500 to-green-600 flex items-center justify-center shadow-lg shadow-emerald-500/20">
178→            <Shield className="w-4 h-4 text-white" />
179→          </div>
180→          <div>
181→            <p className="text-sm font-semibold text-white/90">
182→              Guardrailed Q&A — {metadata.productName}
183→            </p>
184→            <p className="text-xs text-white/35">
185→              {metadata.totalReviews} {metadata.platform} reviews &middot; Dual-layer scope guard active
186→            </p>
187→          </div>
188→        </div>
189→      )}
190→
191→      {/* Messages area */}
192→      <div
193→        ref={scrollContainerRef}
194→        className="flex-1 min-h-0 overflow-y-auto pr-2 scrollbar-thin scrollbar-thumb-white/10 scrollbar-track-transparent"
195→      >
196→        <div className="space-y-4 pb-4">
197→          {messages.length === 0 && (
198→            <div className={cn("text-center animate-fade-in", compact ? "py-8" : "py-16")}>
199→              <div className={cn(
200→                "rounded-2xl bg-linear-to-br from-violet-500/20 to-indigo-500/20 flex items-center justify-center mx-auto border border-violet-500/10",
201→                compact ? "w-12 h-12 mb-3" : "w-16 h-16 mb-5"
202→              )}>
203→                <Bot className={cn(compact ? "w-6 h-6" : "w-8 h-8", "text-violet-400")} />
204→              </div>
205→              <h3 className={cn("font-semibold text-white/80 mb-2", compact ? "text-base" : "text-lg")}>
206→                Ask about the reviews
207→              </h3>
208→              <p className={cn("text-sm text-white/35 max-w-md mx-auto", compact ? "mb-5" : "mb-8")}>
209→                I can analyze the {metadata.totalReviews} ingested {metadata.platform} reviews for{" "}
210→                <strong className="text-white/60">{metadata.productName}</strong>. I&apos;m scoped exclusively to this data.
211→              </p>
212→              <div className={cn("flex flex-wrap gap-2 justify-center", compact ? "max-w-sm" : "max-w-lg", "mx-auto")}>
213→                {SUGGESTED_QUESTIONS.map((q) => (
214→                  <button
215→                    key={q}
216→                    onClick={() => sendMessage(q)}
217→                    className="text-xs px-3.5 py-2 rounded-full glass hover:bg-violet-500/10 hover:border-violet-500/20 transition-all duration-200 text-white/50 hover:text-violet-300"
218→                  >
219→                    <Sparkles className="w-3 h-3 inline mr-1.5 text-violet-400" />
220→                    {q}
221→                  </button>
222→                ))}
223→              </div>
224→            </div>
225→          )}
226→
227→          {messages.map((msg) => (
228→            <div
229→              key={msg.id}
230→              className={cn(
231→                "flex gap-3 animate-fade-up",
232→                msg.role === "user" ? "justify-end" : "justify-start"
233→              )}
234→            >
235→              {msg.role === "assistant" && (
236→                <div
237→                  className={cn(
238→                    "w-8 h-8 rounded-lg flex items-center justify-center shrink-0",
239→                    msg.scopeGuardTriggered
240→                      ? "bg-red-500/20 border border-red-500/20"
241→                      : "bg-violet-500/20 border border-violet-500/20"
242→                  )}
243→                >
244→                  {msg.scopeGuardTriggered ? (
245→                    <ShieldAlert className="w-4 h-4 text-red-400" />
246→                  ) : (
247→                    <Bot className="w-4 h-4 text-violet-400" />
248→                  )}
249→                </div>
250→              )}
251→
252→              <div
253→                className={cn(
254→                  "max-w-[80%] rounded-xl px-4 py-3",
255→                  msg.role === "user"
256→                    ? "bg-linear-to-r from-violet-600 to-indigo-600 text-white shadow-lg shadow-violet-500/15"
257→                    : msg.scopeGuardTriggered
258→                    ? "glass border-red-500/20 bg-red-500/5 glow-red"
259→                    : "glass"
260→                )}
261→              >
262→                {msg.scopeGuardTriggered && (
263→                  <div className="flex items-center gap-1.5 mb-2">
264→                    <ShieldAlert className="w-3 h-3 text-red-400" />
265→                    <span className="text-[10px] font-semibold text-red-400 uppercase tracking-wider">
266→                      Scope Guard — Out of Scope
267→                    </span>
268→                  </div>
269→                )}
270→                <div className={cn(
271→                  "text-sm leading-relaxed",
272→                  msg.role === "user" ? "text-white whitespace-pre-wrap" : "text-white/70"
273→                )}>
274→                  {msg.content ? (
275→                    msg.role === "assistant" ? (
276→                      <>
277→                        <div className="chat-markdown">
278→                          <ReactMarkdown>{msg.content}</ReactMarkdown>
279→                        </div>
280→                        {isStreaming && msg.id === messages[messages.length - 1]?.id && (
281→                          <div className="flex items-center justify-end gap-1 mt-2">
282→                            <div className="w-1.5 h-1.5 rounded-full bg-violet-400 animate-bounce [animation-delay:0ms]" />
283→                            <div className="w-1.5 h-1.5 rounded-full bg-violet-400 animate-bounce [animation-delay:150ms]" />
