  7→import { Tabs, TabsContent, TabsList, TabsTrigger } from "@/components/ui/tabs";
  8→import { Textarea } from "@/components/ui/textarea";
  9→import {
 10→  Globe,
 11→  Upload,
 12→  Loader2,
 13→  CheckCircle2,
 14→  AlertCircle,
 15→  FileText,
 16→} from "lucide-react";
 17→
 18→const PLATFORM_CONFIG: Record<string, { urlSupported: boolean; placeholder: string; helpText: string }> = {
 19→  Amazon: {
 20→    urlSupported: true,
 21→    placeholder: "https://www.amazon.com/dp/B0...",
 22→    helpText: "Enter the Amazon product page URL. Reviews will be extracted automatically.",
 23→  },
 24→  "Google Maps": {
 25→    urlSupported: true,
 26→    placeholder: "https://www.google.com/maps/place/...",
 27→    helpText: "Enter a Google Maps place URL. Reviews will be extracted automatically.",
 28→  },
 29→};
 30→
 31→export default function IngestForm() {
 32→  const router = useRouter();
 33→  const fileInputRef = useRef<HTMLInputElement>(null);
 34→
 35→  const [url, setUrl] = useState("");
 36→  const [csvText, setCsvText] = useState("");
 37→  const [productName, setProductName] = useState("");
 38→  const [platform, setPlatform] = useState("Amazon");
 39→  const [loading, setLoading] = useState(false);
 40→  const [error, setError] = useState("");
 41→  const [fileName, setFileName] = useState("");
 42→
 43→  const config = PLATFORM_CONFIG[platform] || PLATFORM_CONFIG.Other;
 44→
 45→  const handleUrlSubmit = async () => {
 46→    if (!url.trim()) {
 47→      setError("Please enter a product URL");
 48→      return;
 49→    }
 50→    await submitIngest({ type: "url", url: url.trim(), platform });
 51→  };
 52→
 53→  const handleCsvSubmit = async () => {
 54→    if (!csvText.trim()) {
 55→      setError("Please paste CSV data or upload a file");
 56→      return;
 57→    }
 58→    await submitIngest({
 59→      type: "csv",
 60→      csvData: csvText.trim(),
 61→      productName: productName.trim() || "Uploaded Product",
 62→      platform,
 63→    });
 64→  };
 65→
 66→  const handleFileUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
 67→    const file = e.target.files?.[0];
 68→    if (!file) return;
 69→    setFileName(file.name);
 70→    const reader = new FileReader();
 71→    reader.onload = (event) => {
 72→      setCsvText(event.target?.result as string);
 73→    };
 74→    reader.readAsText(file);
 75→  };
 76→
 77→  const submitIngest = async (body: Record<string, string>) => {
 78→    setLoading(true);
