119→          className="w-full rounded-lg glass px-3 py-2.5 text-sm text-white/80 bg-white/5 focus:outline-none focus:ring-2 focus:ring-violet-500/30 transition-all"
120→        >
121→          <option value="Amazon">Amazon</option>
122→          <option value="Google Maps">Google Maps</option>
123→        </select>
124→      </div>
125→
126→      <Tabs defaultValue="url" className="w-full">
127→        <TabsList className="grid w-full grid-cols-2 bg-white/5 rounded-lg p-1">
128→          <TabsTrigger value="url" className="flex items-center gap-2 data-[state=active]:bg-violet-500/20 data-[state=active]:text-violet-300 rounded-md">
