132→          <TabsTrigger value="csv" className="flex items-center gap-2 data-[state=active]:bg-violet-500/20 data-[state=active]:text-violet-300 rounded-md">
133→            <Upload className="w-4 h-4" />
134→            CSV Upload
135→          </TabsTrigger>
136→        </TabsList>
137→
138→        <TabsContent value="url" className="space-y-4 mt-5">
