 1→import {
 2→  ComprehendClient,
 3→  BatchDetectSentimentCommand,
 4→} from "@aws-sdk/client-comprehend";
 5→import { Review, SentimentResult } from "@/types";
 6→
 7→// Uses default AWS credentials chain (profile, env vars, IAM role)
 8→const client = new ComprehendClient({
 9→  region: process.env.AWS_REGION || "us-east-1",
10→});
11→
12→export async function analyzeSentiment(
13→  reviews: Review[]
14→): Promise<Review[]> {
15→  // Comprehend batch limit is 25 documents, each max 5000 bytes
16→  const batchSize = 25;
17→  const enrichedReviews = [...reviews];
18→
19→  for (let i = 0; i < reviews.length; i += batchSize) {
20→    const batch = reviews.slice(i, i + batchSize);
21→    const texts = batch.map((r) => {
22→      const text = `${r.title} ${r.body}`.slice(0, 4900);
23→      // Comprehend requires non-empty text
24→      return text.trim() || "No content";
25→    });
26→
27→    try {
28→      const command = new BatchDetectSentimentCommand({
29→        TextList: texts,
30→        LanguageCode: "en",
31→      });
32→
33→      const response = await client.send(command);
34→
35→      if (response.ResultList) {
36→        for (const result of response.ResultList) {
37→          if (result.Index !== undefined && result.Sentiment) {
38→            const reviewIndex = i + result.Index;
39→            enrichedReviews[reviewIndex] = {
40→              ...enrichedReviews[reviewIndex],
41→              sentiment: {
42→                label: result.Sentiment as SentimentResult["label"],
43→                score:
44→                  result.SentimentScore?.[
45→                    (result.Sentiment.charAt(0) +
46→                      result.Sentiment.slice(1).toLowerCase()) as keyof typeof result.SentimentScore
47→                  ] || 0,
48→              },
49→            };
50→          }
51→        }
52→      }
53→    } catch (error) {
54→      console.error("Comprehend batch sentiment error:", error);
55→      // Fallback: use rating-based sentiment
56→      for (let j = 0; j < batch.length; j++) {
57→        const reviewIndex = i + j;
58→        const rating = batch[j].rating;
59→        enrichedReviews[reviewIndex] = {
60→          ...enrichedReviews[reviewIndex],
61→          sentiment: {
62→            label: rating >= 4 ? "POSITIVE" : rating <= 2 ? "NEGATIVE" : "NEUTRAL",
63→            score: 0.8,
64→          },
65→        };
66→      }
67→    }
68→  }
69→
70→  return enrichedReviews;
71→}
