interface CsvUploadFieldsProps {
  productName: string;
  setProductName: (v: string) => void;
  csvText: string;
  setCsvText: (v: string) => void;
  fileName: string;
  setFileName: (v: string) => void;
  fileInputRef: React.RefObject<HTMLInputElement | null>;
  handleFileUpload: (e: React.ChangeEvent<HTMLInputElement>) => void;
  handleCsvSubmit: () => void;
  loading: boolean;
}

function CsvUploadFields({
  productName,
  setProductName,
  csvText,
  setCsvText,
  fileName,
  setFileName,
  fileInputRef,
  handleFileUpload,
  handleCsvSubmit,
  loading,
}: CsvUploadFieldsProps) {
  const [isDragging, setIsDragging] = useState(false);
  const dragCounter = useRef(0);

  const handleDragEnter = useCallback((e: React.DragEvent) => {
    e.preventDefault();
    e.stopPropagation();
    dragCounter.current++;
    if (e.dataTransfer.items?.length) setIsDragging(true);
  }, []);

  const handleDragLeave = useCallback((e: React.DragEvent) => {
    e.preventDefault();
    e.stopPropagation();
    dragCounter.current--;
    if (dragCounter.current === 0) setIsDragging(false);
  }, []);

  const handleDragOver = useCallback((e: React.DragEvent) => {
    e.preventDefault();
    e.stopPropagation();
  }, []);

  const handleDrop = useCallback((e: React.DragEvent) => {
    e.preventDefault();
    e.stopPropagation();
    setIsDragging(false);
    dragCounter.current = 0;

    const file = e.dataTransfer.files?.[0];
    if (!file) return;

    const ext = file.name.split(".").pop()?.toLowerCase();
    if (ext !== "csv" && ext !== "txt") return;

    setFileName(file.name);
    const reader = new FileReader();
    reader.onload = (event) => {
      setCsvText(event.target?.result as string);
    };
    reader.readAsText(file);
  }, [setCsvText, setFileName]);

  return (
    <>
      <div>
        <label className="text-xs font-medium text-white/50 mb-1.5 block uppercase tracking-wider">
          Product / Business Name
        </label>
        <Input
          placeholder="e.g., Apple AirPods Pro (2nd Gen)"
          value={productName}
          onChange={(e) => setProductName(e.target.value)}
          disabled={loading}
          className="bg-white/5 border-white/10 text-white placeholder:text-white/20 focus:border-violet-500/50 focus:ring-violet-500/20"
        />
      </div>

      <div>
        <label className="text-xs font-medium text-white/50 mb-1.5 block uppercase tracking-wider">
          Upload CSV File
        </label>
        <div
          onClick={() => fileInputRef.current?.click()}
          onDragEnter={handleDragEnter}
          onDragLeave={handleDragLeave}
          onDragOver={handleDragOver}
          onDrop={handleDrop}
          className={`border border-dashed rounded-xl p-8 text-center cursor-pointer transition-all duration-300 group ${
            isDragging
              ? "border-violet-400 bg-violet-500/10 scale-[1.02]"
              : "border-white/15 hover:border-violet-500/40 hover:bg-violet-500/5"
          }`}
        >
          <input
            ref={fileInputRef}
            type="file"
            accept=".csv,.txt"
            onChange={handleFileUpload}
            className="hidden"
          />
          {fileName ? (
            <div className="flex items-center justify-center gap-2 text-sm text-emerald-400">
              <CheckCircle2 className="w-5 h-5" />
              <span>{fileName}</span>
            </div>
